-- Documentation Translations Batch 2: lt, hu, mt, nl, pl
-- Run this in your Supabase SQL Editor

INSERT INTO ui_translations (lang, key, value)
VALUES 
  -- Lithuanian (lt)
  ('lt', 'doc_welcome_title', 'Sveiki atvykę į Aliolo'),
  ('lt', 'doc_welcome_desc', 'Aliolo yra vizualinio mokymosi platforma, sukurta padėti jums įsisavinti dalykus naudojant korteles ir interaktyvų testavimą.'),
  ('lt', 'doc_pillars_title', '8 pagrindiniai pilonai'),
  ('lt', 'doc_pillars_desc', 'Visas „Aliolo“ turinys suskirstytas į 8 pagrindinius pilonus: akademinį ir profesinį, pasaulio, gamtos, žmogaus kūno, humanitarinių mokslų, laisvalaikio, inžinerijos ir kita. Šios kategorijos suteikia struktūrinį pagrindą visiems platformos dalykams.'),
  ('lt', 'doc_leaderboard_title', 'Pasaulinė lyderių lentelė'),
  ('lt', 'doc_leaderboard_desc', 'Konkuruokite su besimokančiaisiais visame pasaulyje! Uždirbkite XP pildydami kortelių sesijas ir kilkite reitinguose. Jūsų pozicija atnaujinama realiuoju laiku, kai įsisavinate naujus dalykus.'),
  ('lt', 'doc_friends_title', 'Draugai ir kvietimai'),
  ('lt', 'doc_friends_desc', 'Mokytis kartu smagiau! Pakvieskite draugus į „Aliolo“ per savo profilį. Galite stebėti vieni kitų pažangą ir išlaikyti motyvaciją matydami, kas išlaiko ilgiausią mokymosi seriją.'),
  ('lt', 'doc_streaks_title', 'Serijų sistema'),
  ('lt', 'doc_streaks_desc', 'Nuoseklumas yra raktas! Kasdien pasiekite savo dienos tikslą, kad sukurtumėte seriją. Nepraleiskite nė vienos dienos, kitaip serija bus nuliūdyta.'),
  ('lt', 'doc_goals_title', 'Dienos tikslai'),
  ('lt', 'doc_goals_desc', 'Nustatymuose nustatykite savo dienos kortelių užbaigimo tikslą. Tikslo pakeitimai įsigalios nuo kitos dienos.'),
  ('lt', 'doc_public_title', 'Viešas prieš privatų'),
  ('lt', 'doc_public_desc', 'Dalykai gali būti privatūs (matomi tik jums) arba vieši. Viešas turinys bendrinamas su visa „Aliolo“ bendruomene, todėl visi gali atrasti jūsų kūrinius ir iš jų mokytis.'),
  ('lt', 'doc_sync_title', 'Debesų sinchronizavimas'),
  ('lt', 'doc_sync_desc', 'Jūsų pažanga automatiškai sinchronizuojama su debesimi. Galite perjungti žiniatinklio ir darbalaukio versijas neprarasdami serijos.'),
  ('lt', 'doc_feedback_title', 'Grįžtamojo ryšio sistema'),
  ('lt', 'doc_feedback_desc', 'Padėkite mums tobulėti! Norėdami pranešti apie problemas, naudokite grįžtamojo ryšio piktogramą (Icons.feedback) prie bet kurio dalyko ar aplanko. Taip pat galite siųsti bendrą programos grįžtamąjį ryšį per palaikymo skiltį.'),
  ('lt', 'doc_lang_title', 'Mokymosi kalba'),
  ('lt', 'doc_lang_desc', 'Prieš pasirinkdami dalyką, viršutiniame meniu visada pasirinkite norimą mokymosi kalbą. Taip užtikrinsite, kad bus įkeltas tinkamas garsas ir vertimai.'),
  ('lt', 'doc_filters_title', 'Paieška ir filtrai'),
  ('lt', 'doc_filters_desc', 'Greitai raskite turinį naudodami paieškos juostą. Galite filtruoti pagal amžiaus grupę (nuo ankstyvosios iki pažengusiųjų) arba susiaurinti vaizdą iki konkrečių kolekcijų ir aplankų.'),
  ('lt', 'doc_flashcards_title', 'Vizualinės kortelės'),
  ('lt', 'doc_flashcards_desc', 'Kiekviename dalyke yra kortelių rinkinys. Nors vaizdai ir garsas palaikomi, jie yra neprivalomi – turinys gali būti grynai tekstinis arba dinamiškai sugeneruotas.'),
  ('lt', 'doc_study_modes_title', 'Adaptyvūs studijų režimai'),
  ('lt', 'doc_study_modes_desc', '„Aliolo“ palaiko įvairius testavimo režimus pagal jūsų turinį: vaizdas į tekstą, garsas į vaizdą ir tekstas į garsą. Šis daugiajutiminis požiūris užtikrina, kad dalykus įsisavinsite visais aspektais.'),
  ('lt', 'doc_testing_title', 'Interaktyvus testavimas'),
  ('lt', 'doc_testing_desc', 'Išbandykite save klausimais su keliais pasirinkimais (MCQ). Programėlė automatiškai judės pirmyn, kai atsakysite, padėdama mokytis greičiau.'),
  ('lt', 'doc_autoplay_title', 'Automatinis mokymasis'),
  ('lt', 'doc_autoplay_desc', 'Atsakius programėlė gali automatiškai pereiti prie kitos kortelės. Teisingi atsakymai laukia 1 s, o neteisingi – 2 s, kad galėtumėte peržiūrėti.'),
  ('lt', 'doc_math_title', 'Matematiniai dalykai'),
  ('lt', 'doc_math_desc', 'Matematiniuose dalykuose naudojami specializuoti varikliai, skirti kortelių vizualizacijoms generuoti realiuoju laiku. Šie dalykai pasižymi unikaliais mokymosi ir testavimo režimais, pritaikytais konkrečioms matematinėms sąvokoms.'),
  ('lt', 'doc_organization_title', 'Turinio organizavimas'),
  ('lt', 'doc_organization_desc', 'Naudokite aplankus susijusiems dalykams grupuoti. Taip pat galite kurti kolekcijas, kad organizuotumėte dalykus į kuruojamus kelius.'),
  ('lt', 'doc_creation_title', 'Dalykų ir kortelių kūrimas'),
  ('lt', 'doc_creation_desc', 'Kurkite savo dalykus ir pridėkite vizualines korteles. Kiekviena kortelė palaiko vaizdą ir pasirinktinį garso failą tarimui.'),
  ('lt', 'doc_collections_purpose_title', 'Kolekcijų tikslas'),
  ('lt', 'doc_collections_purpose_desc', 'Kolekcijos yra kuruojami keliai, jungiantys dalykus. Kai pradedate sesiją iš kolekcijos, sistema sumaišo korteles iš visų įtrauktų dalykų, kad pateiktų atsitiktinį, išsamų testą.'),
  ('lt', 'doc_card_scope_title', 'Kur gyvena kortelės'),
  ('lt', 'doc_card_scope_desc', 'Kortelės yra mokymosi pagrindas ir visada priklauso konkrečiam dalykui. Nors dalykus galite organizuoti į aplankus ar kolekcijas, pačios kortelės turi būti sukurtos dalyko viduje.'),
  ('lt', 'doc_localization_ui_title', 'Vertimų pridėjimas'),
  ('lt', 'doc_localization_ui_desc', 'Norėdami pridėti lokalizuotus duomenis, redaktoriaus antraštėje tiesiog bakstelėkite kalbos kodo piktogramą (pvz., EN, ES, FR). Tai leidžia pateikti konkrečius pavadinimus, aprašymus ir kortelių turinį kiekvienai palaikomai kalbai.'),
  ('lt', 'doc_localization_details_title', 'Kaip veikia lokalizavimas'),
  ('lt', 'doc_localization_details_desc', '„Globali“ kalba yra jūsų pagrindinis atsarginis variantas – tai gali būti bet kuri jūsų pasirinkta kalba. Jei pateiksite konkrečius vertimus, jie pakeis „Globalius“ duomenis tik tada, kai vartotojas pasirinks tą konkrečią vartotojo sąsajos kalbą.'),
  ('lt', 'doc_json_title', 'JSON lokalizavimas'),
  ('lt', 'doc_json_desc', 'Pažangūs kūrėjai gali naudoti JSON duomenis lokalizuotiems pavadinimams ir aprašymams pateikti, kad dalykai būtų prieinami visomis palaikomomis kalbomis.'),
  ('lt', 'doc_media_title', 'Medijos įkėlimo apribojimai'),
  ('lt', 'doc_media_desc', 'Kad užtikrintumėte greitą sinchronizavimą, vaizdus laikykite iki 5 MB, o garso failus – iki 10 MB.'),

  -- Hungarian (hu)
  ('hu', 'doc_welcome_title', 'Üdvözöljük az Aliolóban'),
  ('hu', 'doc_welcome_desc', 'Az Aliolo egy vizuális tanulási platform, amelyet arra terveztek, hogy segítsen elsajátítani a tantárgyakat flashkártyák és interaktív tesztelés segítségével.'),
  ('hu', 'doc_pillars_title', 'A 8 alappillér'),
  ('hu', 'doc_pillars_desc', 'Az Aliolo összes tartalma 8 alappillérbe van szervezve: Akadémiai és szakmai, Világ, Természet, Emberi test, Bölcsészettudományok, Szabadidő, Mérnöki tudományok és Egyéb. Ezek a kategóriák strukturált keretet biztosítanak a platform összes tantárgyához.'),
  ('hu', 'doc_leaderboard_title', 'Globális ranglista'),
  ('hu', 'doc_leaderboard_desc', 'Versenyezz tanulókkal világszerte! Szerezz XP-t kártyamenetek teljesítésével, és mássz fel a ranglistán. Pozíciód valós időben frissül, amint új tantárgyakat sajátítasz el.'),
  ('hu', 'doc_friends_title', 'Barátok és meghívók'),
  ('hu', 'doc_friends_desc', 'A tanulás jobb együtt! Hívj meg barátokat az Aliolóba a profilodon keresztül. Követhetitek egymás fejlődését, és motiváltak maradhattok, ha látjátok, ki tartja a leghosszabb sorozatot.'),
  ('hu', 'doc_streaks_title', 'Sorozat rendszer'),
  ('hu', 'doc_streaks_desc', 'A következetesség a kulcs! Teljesítsd napi célodat minden nap a sorozatod építéséhez. Ne hagyj ki egyetlen napot sem, különben a sorozat alaphelyzetbe áll.'),
  ('hu', 'doc_goals_title', 'Napi célok'),
  ('hu', 'doc_goals_desc', 'Állítsd be napi kártyateljesítési célodat a beállításokban. A célod módosításai a következő naptól lépnek életbe.'),
  ('hu', 'doc_public_title', 'Nyilvános vs Privát'),
  ('hu', 'doc_public_desc', 'A tantárgyak lehetnek privátak (csak számodra láthatóak) vagy nyilvánosak. A nyilvános tartalmakat megosztjuk az egész Aliolo közösséggel, lehetővé téve mindenki számára, hogy felfedezze és tanuljon az alkotásaidból.'),
  ('hu', 'doc_sync_title', 'Felhő szinkronizálás'),
  ('hu', 'doc_sync_desc', 'Fejlődésed automatikusan szinkronizálódik a felhőbe. Váltogathatsz a webes és az asztali verziók között anélkül, hogy elveszítenéd a sorozatodat.'),
  ('hu', 'doc_feedback_title', 'Visszajelzési rendszer'),
  ('hu', 'doc_feedback_desc', 'Segíts nekünk fejlődni! Használd a visszajelzés ikont (Icons.feedback) bármely tantárgynál vagy mappánál a problémák bejelentéséhez. Általános alkalmazás-visszajelzést is küldhetsz a Támogatás szekción keresztül.'),
  ('hu', 'doc_lang_title', 'Tanulási nyelv'),
  ('hu', 'doc_lang_desc', 'Mindig válaszd ki a preferált tanulási nyelvet a felső menüben, mielőtt tantárgyat választanál. Ez biztosítja a megfelelő hanganyag és fordítások betöltését.'),
  ('hu', 'doc_filters_title', 'Keresés és szűrők'),
  ('hu', 'doc_filters_desc', 'Találd meg gyorsan a tartalmakat a keresősáv segítségével. Szűrhetsz korcsoport szerint (korai-haladó), vagy szűkítheted a nézetet konkrét gyűjteményekre és mappákra.'),
  ('hu', 'doc_flashcards_title', 'Vizuális flashkártyák'),
  ('hu', 'doc_flashcards_desc', 'Minden tantárgy egy kártyakészletet tartalmaz. Bár a képek és a hang támogatottak, opcionálisak – a tartalom lehet tisztán szöveges vagy dinamikusan generált.'),
  ('hu', 'doc_study_modes_title', 'Adaptív tanulási módok'),
  ('hu', 'doc_study_modes_desc', 'Az Aliolo különféle tesztelési módokat támogat a tartalom alapján: Kép-Szöveg, Hang-Kép és Szöveg-Hang. Ez a több érzékszervre ható megközelítés biztosítja, hogy minden szögből elsajátítsd a tantárgyakat.'),
  ('hu', 'doc_testing_title', 'Interaktív tesztelés'),
  ('hu', 'doc_testing_desc', 'Hívd ki magad feleletválasztós kérdésekkel (MCQ). Az alkalmazás automatikusan továbblép, amint válaszolsz, segítve a gyorsabb tanulást.'),
  ('hu', 'doc_autoplay_title', 'Automatikus lejátszás'),
  ('hu', 'doc_autoplay_desc', 'Az alkalmazás a válaszadás után automatikusan továbbléphet a következő kártyára. A helyes válaszok 1 másodpercet, míg a helytelenek 2 másodpercet várnak, hogy átnézhesd őket.'),
  ('hu', 'doc_math_title', 'Matematikai tantárgyak'),
  ('hu', 'doc_math_desc', 'A matematikai tantárgyak speciális motorokat használnak a kártyavizualizációk valós idejű generálásához. Ezek a tantárgyak egyedi, konkrét matematikai fogalmakra szabott tanulási és tesztelési módokkal rendelkeznek.'),
  ('hu', 'doc_organization_title', 'Tartalom rendszerezése'),
  ('hu', 'doc_organization_desc', 'Használj mappákat a kapcsolódó tantárgyak csoportosításához. Gyűjteményeket is létrehozhatsz a tantárgyak kurátori útvonalakba rendezéséhez.'),
  ('hu', 'doc_creation_title', 'Tantárgyak és kártyák létrehozása'),
  ('hu', 'doc_creation_desc', 'Hozd létre saját tantárgyaidat, és adj hozzá vizuális flashkártyákat. Minden kártya támogat egy képet és egy opcionális hangfájlt a kiejtéshez.'),
  ('hu', 'doc_collections_purpose_title', 'A gyűjtemények célja'),
  ('hu', 'doc_collections_purpose_desc', 'A gyűjtemények kurátori útvonalak, amelyek tantárgyakat csoportosítanak. Ha gyűjteményből indítasz menetet, a rendszer összekeveri az összes benne lévő tantárgy kártyáit a véletlenszerű, átfogó teszt érdekében.'),
  ('hu', 'doc_card_scope_title', 'Hol laknak a kártyák'),
  ('hu', 'doc_card_scope_desc', 'A kártyák a tanulás építőkövei, és mindig egy konkrét tantárgyhoz tartoznak. Bár a tantárgyakat mappákba vagy gyűjteményekbe rendezheted, magukat a kártyákat egy tantárgyon belül kell létrehozni.'),
  ('hu', 'doc_localization_ui_title', 'Fordítások hozzáadása'),
  ('hu', 'doc_localization_ui_desc', 'Lokalizált adatok hozzáadásához egyszerűen koppints a nyelv kódja ikonra (pl. EN, ES, FR) a szerkesztő fejlécében. Ez lehetővé teszi, hogy minden támogatott nyelvhez egyedi neveket, leírásokat és kártyatartalmakat adj meg.'),
  ('hu', 'doc_localization_details_title', 'Hogyan működik a lokalizáció'),
  ('hu', 'doc_localization_details_desc', 'A „Globális” nyelv az elsődleges tartalékod – ez bármilyen nyelv lehet, amit választasz. Ha konkrét fordításokat adsz meg, azok csak akkor írják felül a globális adatokat, ha a felhasználó azt a konkrét UI nyelvet választja.'),
  ('hu', 'doc_json_title', 'JSON lokalizáció'),
  ('hu', 'doc_json_desc', 'A haladó alkotók JSON adatok segítségével lokalizált neveket és leírásokat adhatnak meg, így a tantárgyak minden támogatott nyelven elérhetővé válnak.'),
  ('hu', 'doc_media_title', 'Médiafeltöltési korlátok'),
  ('hu', 'doc_media_desc', 'A gyors szinkronizálás érdekében a képeket 5 MB, a hangfájlokat pedig 10 MB alatt tartsd.'),

  -- Maltese (mt)
  ('mt', 'doc_welcome_title', 'Merħba f''Aliolo'),
  ('mt', 'doc_welcome_desc', 'Aliolo hija pjattaforma ta'' tagħlim viżiv iddisinjata biex tgħinek tikkontrolla s-suġġetti permezz ta'' flashcards u ttestjar interattiv.'),
  ('mt', 'doc_pillars_title', 'It-8 Pilastri Ewlenin'),
  ('mt', 'doc_pillars_desc', 'Il-kontenut kollu f''Aliolo huwa organizzat fi 8 pilastri fundamentali: Akkademiku u Professjonali, Dinja, Natura, Korp tal-Bniedem, Umanitajiet, Divertiment, Inġinerija, u Oħrajn. Dawn il-kategoriji jipprovdu qafas strutturat għas-suġġetti kollha madwar il-pjattaforma.'),
  ('mt', 'doc_leaderboard_title', 'Leaderboard Globali'),
  ('mt', 'doc_leaderboard_desc', 'Ikkompeti ma'' studenti madwar id-dinja! Aqla'' XP billi tlesti sessjonijiet ta'' kards u itla'' fil-klassifika. Il-pożizzjoni tiegħek tiġi aġġornata f''ħin reali hekk kif tikkontrolla suġġetti ġodda.'),
  ('mt', 'doc_friends_title', 'Ħbieb u Stediniet'),
  ('mt', 'doc_friends_desc', 'It-tagħlim huwa aħjar flimkien! Stieden ħbieb f''Aliolo permezz tal-profil tiegħek. Tista'' ssegwi l-progress ta'' xulxin u tibqa'' mmotivata billi tara min iżomm l-itwal streak.'),
  ('mt', 'doc_streaks_title', 'Sistema ta'' Streak'),
  ('mt', 'doc_streaks_desc', 'Il-konsistenza hija essenzjali! Tlesti l-mira tiegħek ta'' kuljum biex tibni l-istreak tiegħek. Titlifx ġurnata, inkella l-istreak jerġa'' lura għal żero.'),
  ('mt', 'doc_goals_title', 'Għanijiet ta'' Kuljum'),
  ('mt', 'doc_goals_desc', 'Issettja l-mira tiegħek ta'' tlestija tal-kards ta'' kuljum fis-settings. Il-bidliet fil-mira tiegħek jidħlu fis-seħħ mill-għada.'),
  ('mt', 'doc_public_title', 'Pubbliku vs Privat'),
  ('mt', 'doc_public_desc', 'Is-suġġetti jistgħu jkunu privati (viżibbli għalik biss) jew pubbliċi. Kontenut pubbliku huwa kondiviż mal-komunità kollha ta'' Aliolo, li jippermetti lil kulħadd jiskopri u jitgħallem mill-kreazzjonijiet tiegħek.'),
  ('mt', 'doc_sync_title', 'Sinkronizzazzjoni tal-Cloud'),
  ('mt', 'doc_sync_desc', 'Il-progress tiegħek huwa sinkronizzat awtomatikament mal-cloud. Tista'' taqleb bejn il-verżjonijiet tal-web u tad-desktop mingħajr ma titlef l-istreak tiegħek.'),
  ('mt', 'doc_feedback_title', 'Sistema ta'' Feedback'),
  ('mt', 'doc_feedback_desc', 'Għinna ntejbu! Uża l-ikona tal-feedback (Icons.feedback) fuq kwalunkwe Suġġett jew Folder biex tirrapporta problemi. Tista'' wkoll tibgħat feedback ġenerali dwar l-app permezz tas-sezzjoni tas-Sostenn.'),
  ('mt', 'doc_lang_title', 'Lingwa tat-Tagħlim'),
  ('mt', 'doc_lang_desc', 'Dejjem agħżel il-lingwa tat-tagħlim preferuta tiegħek fil-menu ta'' fuq qabel ma tagħżel suġġett. Dan jiżgura li l-awdjo u t-traduzzjonijiet korretti jitgħabbew.'),
  ('mt', 'doc_filters_title', 'Fittex u Filtri'),
  ('mt', 'doc_filters_desc', 'Sib il-kontenut malajr billi tuża l-istrixxa tat-tfittxija. Tista'' tiffiltra skont il-Grupp tal-Età (Kmieni sa Avvanzat) jew tnaqqas il-viżjoni tiegħek għal Kollezzjonijiet u Folders speċifiċi.'),
  ('mt', 'doc_flashcards_title', 'Flashcards Viżwali'),
  ('mt', 'doc_flashcards_desc', 'Kull suġġett fih sett ta'' kards. Filwaqt li stampi u awdjo huma appoġġjati, huma fakultattivi—il-kontenut jista'' jkun purament testwali jew iġġenerat b''mod dinamiku.'),
  ('mt', 'doc_study_modes_title', 'Modi ta'' Studju Adattivi'),
  ('mt', 'doc_study_modes_desc', 'Aliolo jappoġġja diversi modi ta'' ttestjar ibbażati fuq il-kontenut tiegħek: Immaġni-għal-Test, Awdjo-għal-Immaġni, u Test-għal-Awdjo. Dan l-approċċ multi-sensorju jiżgura li tikkontrolla s-suġġetti minn kull angolu.'),
  ('mt', 'doc_testing_title', 'Ittestjar Interattiv'),
  ('mt', 'doc_testing_desc', 'Sfida lilek innifsek b''mistoqsijiet b''għażla multipla (MCQ). L-app tavvanza awtomatikament hekk kif twieġeb, u tgħinek titgħallem aktar malajr.'),
  ('mt', 'doc_autoplay_title', 'Tagħlim Auto-Play'),
  ('mt', 'doc_autoplay_desc', 'L-app tista'' tavvanza awtomatikament għall-kard li jmiss wara li twieġeb. Tweġibiet korretti jistennew 1s, filwaqt li dawk żbaljati jistennew 2s biex iħalluk tirrevedi.'),
  ('mt', 'doc_math_title', 'Suġġetti Matematiċi'),
  ('mt', 'doc_math_desc', 'Suġġetti matematiċi jużaw magni speċjalizzati biex jiġġeneraw viżwalizzazzjonijiet tal-kards f''ħin reali. Dawn is-suġġetti għandhom modi uniku ta'' tagħlim u ttestjar adattati għal kunċetti matematiċi speċifiċi.'),
  ('mt', 'doc_organization_title', 'Organizzazzjoni tal-Kontenut'),
  ('mt', 'doc_organization_desc', 'Uża Folders biex tiġbor flimkien Suġġetti relatati. Tista'' wkoll toħloq Kollezzjonijiet biex torganizza s-Suġġetti f''mogħdijiet ikkurati.'),
  ('mt', 'doc_creation_title', 'Ħolqien ta'' Suġġetti u Kards'),
  ('mt', 'doc_creation_desc', 'Oħloq is-Suġġetti tiegħek u żid Flashcards viżwali. Kull kard tappoġġja immaġni u fajl awdjo fakultattiv għall-pronunzja.'),
  ('mt', 'doc_collections_purpose_title', 'L-Għan tal-Kollezzjonijiet'),
  ('mt', 'doc_collections_purpose_desc', 'Il-kollezzjonijiet huma mogħdijiet ikkurati li jiġbru s-Suġġetti flimkien. Meta tibda sessjoni minn Kollezzjoni, is-sistema tħallat kards mis-suġġetti kollha inklużi biex tipprovdi test każwali u komprensiv.'),
  ('mt', 'doc_card_scope_title', 'Fejn joqogħdu l-kards'),
  ('mt', 'doc_card_scope_desc', 'Il-kards huma l-elementi bażiċi tat-tagħlim u dejjem jappartjenu għal Suġġett speċifiku. Filwaqt li tista'' torganizza s-Suġġetti f''Folders jew Kollezzjonijiet, il-kards infushom għandhom jinħolqu fi ħdan Suġġett.'),
  ('mt', 'doc_localization_ui_title', 'Żieda ta'' Traduzzjonijiet'),
  ('mt', 'doc_localization_ui_desc', 'Biex iżżid data lokalizzata, sempliċement taptap l-ikona tal-kodiċi tal-lingwa (eż., EN, ES, FR) fil-header tal-editur. Dan jippermettilek tipprovdi ismijiet speċifiċi, deskrizzjonijiet, u kontenut tal-kards għal kull lingwa appoġġjata.'),
  ('mt', 'doc_localization_details_title', 'Kif taħdem il-Lokalizzazzjoni'),
  ('mt', 'doc_localization_details_desc', 'Il-lingwa "Globali" hija l-fallback prinċipali tiegħek—tista'' tkun kwalunkwe lingwa li tagħżel. Jekk tipprovdi traduzzjonijiet speċifiċi, dawn jissostitwixxu d-data Globali biss meta utent jagħżel dik il-lingwa speċifika tal-UI.'),
  ('mt', 'doc_json_title', 'Lokalizzazzjoni JSON'),
  ('mt', 'doc_json_desc', 'Il-ħallieqa avvanzati jistgħu jużaw data JSON biex jipprovdu ismijiet u deskrizzjonijiet lokalizzati, u b''hekk is-suġġetti jkunu aċċessibbli fil-lingwi kollha appoġġjati.'),
  ('mt', 'doc_media_title', 'Limiti ta'' Upload tal-Midja'),
  ('mt', 'doc_media_desc', 'Biex tiżgura sinkronizzazzjoni mgħaġġla, żomm l-immaġini taħt il-5MB u l-fajls awdjo taħt l-10MB.'),

  -- Dutch (nl)
  ('nl', 'doc_welcome_title', 'Welkom bij Aliolo'),
  ('nl', 'doc_welcome_desc', 'Aliolo is een visueel leerplatform ontworpen om je te helpen onderwerpen onder de knie te krijgen via flashcards en interactieve tests.'),
  ('nl', 'doc_pillars_title', 'De 8 kernpijlers'),
  ('nl', 'doc_pillars_desc', 'Alle inhoud in Aliolo is georganiseerd in 8 basispijlers: Academisch & Professioneel, Wereld, Natuur, Menselijk Lichaam, Geesteswetenschappen, Vrije tijd, Engineering en Overig. Deze categorieën bieden een gestructureerd kader voor alle onderwerpen op het platform.'),
  ('nl', 'doc_leaderboard_title', 'Wereldwijd klassement'),
  ('nl', 'doc_leaderboard_desc', 'Concurreer met leerlingen wereldwijd! Verdien XP door kaartsessies te voltooien en stijg op de ranglijst. Je positie wordt in realtime bijgewerkt terwijl je nieuwe onderwerpen onder de knie krijgt.'),
  ('nl', 'doc_friends_title', 'Vrienden & uitnodigingen'),
  ('nl', 'doc_friends_desc', 'Samen leren is leuker! Nodig vrienden uit voor Aliolo via je profiel. Je kunt elkaars voortgang volgen en gemotiveerd blijven door te zien wie de langste streak behoudt.'),
  ('nl', 'doc_streaks_title', 'Streak-systeem'),
  ('nl', 'doc_streaks_desc', 'Consistentie is de sleutel! Voltooi elke dag je dagelijkse doel om je streak op te bouwen. Mis geen dag, anders wordt de streak gereset.'),
  ('nl', 'doc_goals_title', 'Dagelijkse doelen'),
  ('nl', 'doc_goals_desc', 'Stel je dagelijkse doel voor het voltooien van kaarten in bij de instellingen. Wijzigingen in je doel worden de volgende dag van kracht.'),
  ('nl', 'doc_public_title', 'Openbaar vs. privé'),
  ('nl', 'doc_public_desc', 'Onderwerpen kunnen privé zijn (alleen zichtbaar voor jou) of openbaar. Openbare inhoud wordt gedeeld met de hele Aliolo-gemeenschap, zodat iedereen je creaties kan ontdekken en ervan kan leren.'),
  ('nl', 'doc_sync_title', 'Cloud-synchronisatie'),
  ('nl', 'nl', 'doc_sync_desc', 'Je voortgang wordt automatisch gesynchroniseerd met de cloud. Je kunt schakelen tussen web- en desktopversies zonder je streak te verliezen.'),
  ('nl', 'doc_feedback_title', 'Feedback-systeem'),
  ('nl', 'doc_feedback_desc', 'Help ons verbeteren! Gebruik het feedback-icoon (Icons.feedback) op een onderwerp of map om problemen te melden. Je kunt ook algemene app-feedback sturen via de sectie Ondersteuning.'),
  ('nl', 'doc_lang_title', 'Leertaal'),
  ('nl', 'doc_lang_desc', 'Selecteer altijd de leertaal van je voorkeur in het bovenmenu voordat je een onderwerp selecteert. Dit zorgt ervoor dat de juiste audio en vertalingen worden geladen.'),
  ('nl', 'doc_filters_title', 'Zoeken & filters'),
  ('nl', 'doc_filters_desc', 'Vind snel inhoud met de zoekbalk. Je kunt filteren op leeftijdsgroep (van beginnend tot gevorderd) of je weergave beperken tot specifieke collecties en mappen.'),
  ('nl', 'doc_flashcards_title', 'Visuele flashcards'),
  ('nl', 'doc_flashcards_desc', 'Elk onderwerp bevat een set kaarten. Hoewel afbeeldingen en audio worden ondersteund, zijn ze optioneel: inhoud kan puur tekstueel zijn of dynamisch worden gegenereerd.'),
  ('nl', 'doc_study_modes_title', 'Adaptieve studiemodi'),
  ('nl', 'doc_study_modes_desc', 'Aliolo ondersteunt verschillende testmodi op basis van je inhoud: Afbeelding-naar-tekst, Audio-naar-afbeelding en Tekst-naar-audio. Deze multisensorische aanpak zorgt ervoor dat je onderwerpen vanuit elke hoek beheerst.'),
  ('nl', 'doc_testing_title', 'Interactief testen'),
  ('nl', 'doc_testing_desc', 'Daag jezelf uit met meerkeuzevragen (MCQ). De app gaat automatisch verder terwijl je antwoordt, waardoor je sneller leert.'),
  ('nl', 'doc_autoplay_title', 'Automatisch afspelen'),
  ('nl', 'doc_autoplay_desc', 'De app kan na je antwoord automatisch doorgaan naar de volgende kaart. Bij goede antwoorden wacht de app 1 sec., bij foute antwoorden 2 sec. zodat je ze kunt bekijken.'),
  ('nl', 'doc_math_title', 'Wiskundige onderwerpen'),
  ('nl', 'doc_math_desc', 'Wiskundige onderwerpen gebruiken gespecialiseerde engines om kaartvisualisaties in realtime te genereren. Deze onderwerpen hebben unieke leer- en testmodi die zijn afgestemd op specifieke wiskundige concepten.'),
  ('nl', 'doc_organization_title', 'Inhoud organiseren'),
  ('nl', 'doc_organization_desc', 'Gebruik mappen om gerelateerde onderwerpen te groeperen. Je kunt ook collecties maken om onderwerpen in gecureerde paden te organiseren.'),
  ('nl', 'doc_creation_title', 'Onderwerpen & kaarten maken'),
  ('nl', 'doc_creation_desc', 'Maak je eigen onderwerpen en voeg visuele flashcards toe. Elke kaart ondersteunt een afbeelding en een optioneel audiobestand voor de uitspraak.'),
  ('nl', 'doc_collections_purpose_title', 'Het doel van collecties'),
  ('nl', 'doc_collections_purpose_desc', 'Collecties zijn gecureerde paden die onderwerpen groeperen. Wanneer je een sessie start vanuit een collectie, mixt het systeem kaarten van alle inbegrepen onderwerpen voor een uitgebreide test.'),
  ('nl', 'doc_card_scope_title', 'Waar kaarten wonen'),
  ('nl', 'doc_card_scope_desc', 'Kaarten zijn de bouwstenen van het leren en horen altijd bij een specifiek onderwerp. Hoewel je onderwerpen kunt organiseren in mappen of collecties, moeten kaarten zelf binnen een onderwerp worden gemaakt.'),
  ('nl', 'doc_localization_ui_title', 'Vertalingen toevoegen'),
  ('nl', 'doc_localization_ui_desc', 'Tik op het taalcode-icoon (bijv. EN, ES, FR) in de header om gelokaliseerde gegevens toe te voegen. Hiermee kun je specifieke namen, beschrijvingen en kaartinhoud opgeven voor elke ondersteunde taal.'),
  ('nl', 'doc_localization_details_title', 'Hoe lokalisatie werkt'),
  ('nl', 'doc_localization_details_desc', 'De „Globale” taal is je primaire fallback — dit kan elke taal zijn die je kiest. Als je specifieke vertalingen opgeeft, overschrijven deze de globale gegevens alleen wanneer een gebruiker die specifieke UI-taal selecteert.'),
  ('nl', 'doc_json_title', 'JSON-lokalisatie'),
  ('nl', 'doc_json_desc', 'Geavanceerde makers kunnen JSON-gegevens gebruiken om gelokaliseerde namen en beschrijvingen op te geven, waardoor onderwerpen toegankelijk worden in alle ondersteunde talen.'),
  ('nl', 'doc_media_title', 'Media-uploadlimieten'),
  ('nl', 'doc_media_desc', 'Houd afbeeldingen onder de 5 MB en audiobestanden onder de 10 MB voor een snelle synchronisatie.'),

  -- Polish (pl)
  ('pl', 'doc_welcome_title', 'Witamy w Aliolo'),
  ('pl', 'doc_welcome_desc', 'Aliolo to wizualna platforma edukacyjna zaprojektowana, aby pomóc Ci opanować tematy poprzez fiszki i interaktywne testy.'),
  ('pl', 'doc_pillars_title', '8 głównych filarów'),
  ('pl', 'doc_pillars_desc', 'Cała zawartość Aliolo jest zorganizowana w 8 fundamentalnych filarów: Akademicki i zawodowy, Świat, Natura, Ciało ludzkie, Nauki humanistyczne, Czas wolny, Inżynieria i Inne. Kategorie te stanowią strukturalną ramę dla wszystkich tematów na platformie.'),
  ('pl', 'doc_leaderboard_title', 'Globalny ranking'),
  ('pl', 'doc_leaderboard_desc', 'Rywalizuj z uczniami z całego świata! Zdobywaj XP za ukończone sesje kart i wspinaj się w rankingu. Twoja pozycja jest aktualizowana w czasie rzeczywistym w miarę opanowywania nowych tematów.'),
  ('pl', 'doc_friends_title', 'Znajomi i zaproszenia'),
  ('pl', 'doc_friends_desc', 'Nauka jest lepsza razem! Zaproś znajomych do Aliolo za pośrednictwem swojego profilu. Możecie śledzić nawzajem swoje postępy i zachować motywację, widząc, kto utrzymuje najdłuższą serię.'),
  ('pl', 'doc_streaks_title', 'System serii'),
  ('pl', 'doc_streaks_desc', 'Konsekwencja jest kluczem! Realizuj swój dzienny cel każdego dnia, aby budować swoją serię. Nie opuszczaj żadnego dnia, inaczej seria zostanie zresetowana.'),
  ('pl', 'doc_goals_title', 'Cele dzienne'),
  ('pl', 'doc_goals_desc', 'Ustaw swój dzienny cel ukończenia kart w ustawieniach. Zmiany w celu wejdą w życie od następnego dnia.'),
  ('pl', 'doc_public_title', 'Publiczne vs Prywatne'),
  ('pl', 'doc_public_desc', 'Tematy mogą być prywatne (widoczne tylko dla Ciebie) lub publiczne. Treści publiczne są udostępniane całej społeczności Aliolo, co pozwala każdemu odkrywać i uczyć się z Twoich dzieł.'),
  ('pl', 'doc_sync_title', 'Synchronizacja w chmurze'),
  ('pl', 'doc_sync_desc', 'Twoje postępy są automatycznie synchronizowane z chmurą. Możesz przełączać się między wersją internetową a stacjonarną bez utraty serii.'),
  ('pl', 'doc_feedback_title', 'System opinii'),
  ('pl', 'doc_feedback_desc', 'Pomóż nam się doskonalić! Użyj ikony opinii (Icons.feedback) przy dowolnym temacie lub folderze, aby zgłosić problemy. Możesz również wysłać ogólną opinię o aplikacji za pośrednictwem sekcji Wsparcie.'),
  ('pl', 'doc_lang_title', 'Język nauki'),
  ('pl', 'doc_lang_desc', 'Zawsze wybieraj preferowany język nauki w górnym menu przed wyborem tematu. Zapewnia to załadowanie poprawnego dźwięku i tłumaczeń.'),
  ('pl', 'doc_filters_title', 'Wyszukiwanie i filtry'),
  ('pl', 'doc_filters_desc', 'Szybko znajduj treści za pomocą paska wyszukiwania. Możesz filtrować według grupy wiekowej (od wczesnej do zaawansowanej) lub zawęzić widok do konkretnych kolekcji i folderów.'),
  ('pl', 'doc_flashcards_title', 'Wizualne fiszki'),
  ('pl', 'doc_flashcards_desc', 'Każdy temat zawiera zestaw kart. Chociaż obrazy i dźwięk są obsługiwane, są one opcjonalne – treść może być czysto tekstowa lub generowana dynamicznie.'),
  ('pl', 'doc_study_modes_title', 'Adaptacyjne tryby nauki'),
  ('pl', 'doc_study_modes_desc', 'Aliolo obsługuje różne tryby testowania w zależności od treści: Obraz-Tekst, Dźwięk-Obraz i Tekst-Dźwięk. To wielozmysłowe podejście zapewnia opanowanie tematów pod każdym kątem.'),
  ('pl', 'doc_testing_title', 'Interaktywne testy'),
  ('pl', 'doc_testing_desc', 'Rzuć sobie wyzwanie za pomocą pytań wielokrotnego wyboru (MCQ). Aplikacja będzie automatycznie przechodzić dalej w miarę udzielania odpowiedzi, pomagając Ci szybciej się uczyć.'),
  ('pl', 'doc_autoplay_title', 'Automatyczne odtwarzanie'),
  ('pl', 'doc_autoplay_desc', 'Aplikacja może automatycznie przechodzić do następnej karty po udzieleniu odpowiedzi. Poprawne odpowiedzi czekają 1 s, a błędne 2 s, aby umożliwić Ci przejrzenie karty.'),
  ('pl', 'doc_math_title', 'Tematy matematyczne'),
  ('pl', 'doc_math_desc', 'Tematy matematyczne wykorzystują wyspecjalizowane silniki do generowania wizualizacji kart w czasie rzeczywistym. Tematy te oferują unikalne tryby nauki i testowania dostosowane do konkretnych pojęć matematycznych.'),
  ('pl', 'doc_organization_title', 'Organizowanie treści'),
  ('pl', 'doc_organization_desc', 'Używaj folderów, aby grupować powiązane tematy. Możesz także tworzyć kolekcje, aby organizować tematy w wyselekcjonowane ścieżki.'),
  ('pl', 'doc_creation_title', 'Tworzenie tematów i kart'),
  ('pl', 'doc_creation_desc', 'Twórz własne tematy i dodawaj wizualne fiszki. Każda karta obsługuje obraz i opcjonalny plik dźwiękowy z wymową.'),
  ('pl', 'doc_collections_purpose_title', 'Cel kolekcji'),
  ('pl', 'doc_collections_purpose_desc', 'Kolekcje to wyselekcjonowane ścieżki, które grupują tematy. Po rozpoczęciu sesji z kolekcji, system miesza karty ze wszystkich zawartych w niej tematów, aby zapewnić kompleksowy test.'),
  ('pl', 'doc_card_scope_title', 'Gdzie mieszkają karty'),
  ('pl', 'doc_card_scope_desc', 'Karty są budulcem nauki i zawsze należą do konkretnego tematu. Chociaż możesz organizować tematy w foldery lub kolekcje, same karty muszą być tworzone w obrębie tematu.'),
  ('pl', 'doc_localization_ui_title', 'Dodawanie tłumaczeń'),
  ('pl', 'doc_localization_ui_desc', 'Aby dodać zlokalizowane dane, po prostu dotknij ikony kodu języka (np. EN, ES, FR) w nagłówku edytora. Pozwala to na podanie konkretnych nazw, opisów i treści kart dla każdego obsługiwanego języka.'),
  ('pl', 'doc_localization_details_title', 'Jak działa lokalizacja'),
  ('pl', 'doc_localization_details_desc', 'Język „Globalny” jest podstawowym językiem rezerwowym – może to być dowolny wybrany przez Ciebie język. Jeśli podasz konkretne tłumaczenia, zastąpią one dane globalne tylko wtedy, gdy użytkownik wybierze ten konkretny język interfejsu.'),
  ('pl', 'doc_json_title', 'Lokalizacja JSON'),
  ('pl', 'doc_json_desc', 'Zaawansowani twórcy mogą używać danych JSON do podawania zlokalizowanych nazw i opisów, dzięki czemu tematy są dostępne we wszystkich obsługiwanych językach.'),
  ('pl', 'doc_media_title', 'Limity przesyłania mediów'),
  ('pl', 'doc_media_desc', 'Aby zapewnić szybką synchronizację, obrazy powinny mieć mniej niż 5 MB, a pliki dźwiękowe mniej niż 10 MB.')
ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
